 8→/**
 9→ * Get interest-based explore sections for a user.
10→ * Fetches the user's writing_interests, looks up cached topic embeddings,
11→ * and calls get_interest_posts RPC in parallel for each interest.
12→ */
13→export const getInterestSectionsService = async (userId) => {
14→    if (!userId) {
15→        throw { status: 401, error: 'authentication required' };
16→    }
17→
18→    // Fetch user's writing interests
19→    const { data: userData, error: userError } = await supabase
20→        .from('users')
21→        .select('writing_interests')
22→        .eq('id', userId)
23→        .single();
24→
25→    if (userError) {
26→        console.error('supabase error fetching user interests:', userError.message);
27→        throw { status: 500, error: 'failed to fetch user interests' };
28→    }
29→
30→    const interests = userData?.writing_interests;
31→    if (!Array.isArray(interests) || interests.length === 0) {
32→        return { sections: [] };
33→    }
34→
35→    // Cap at MAX_INTEREST_SECTIONS
36→    const capped = interests.slice(0, MAX_INTEREST_SECTIONS);
37→
38→    // Build queries in parallel — skip interests without a cached embedding
39→    const sectionPromises = capped.map(async (interest) => {
40→        const embedding = getTopicEmbedding(interest);
41→        if (!embedding) {
42→            return null;
43→        }
44→
45→        try {
46→            const { data: posts, error: rpcError } = await supabase.rpc('get_interest_posts', {
47→                p_topic_embedding: embedding,
48→                p_limit: 8,
49→                p_recency_days: 30
50→            });
51→
52→            if (rpcError) {
53→                console.error(`RPC error for interest "${interest}":`, rpcError.message);
54→                return null;
55→            }
56→
57→            if (!posts || posts.length < MIN_POSTS_PER_SECTION) {
58→                return null;
59→            }
60→
61→            return {
62→                interest,
63→                posts: posts.map((row) => {
64→                    const thumbnailMedia = createMediaResponsePayload('journal-images', row.thumbnail_url, 'feed_banner');
65→                    const userAvatarMedia = createMediaResponsePayload('avatars', row.user_image_url, 'card');
66→
67→                    return {
68→                        id: row.id,
69→                        user_id: row.user_id,
70→                        title: row.title,
71→                        preview_text: row.preview_text || '',
72→                        thumbnail_url: thumbnailMedia?.preferred_url || row.thumbnail_url || null,
73→                        thumbnail_media: thumbnailMedia,
74→                        post_type: row.post_type,
75→                        created_at: row.created_at,
76→                        views: row.views,
77→                        user_name: row.user_name,
78→                        user_image_url: userAvatarMedia?.preferred_url || row.user_image_url || null,
79→                        user_avatar_media: userAvatarMedia,
80→                        user_badge: row.user_badge,
81→                        username: row.username,
82→                        like_count: Number(row.like_count),
83→                        comment_count: Number(row.comment_count),
84→                        bookmark_count: Number(row.bookmark_count),
85→                    };
86→                })
87→            };
88→        } catch (err) {
89→            console.error(`Error fetching interest posts for "${interest}":`, err?.message || err);
90→            return null;
91→        }
92→    });
93→
94→    const results = await Promise.all(sectionPromises);
95→    const sections = results.filter(Boolean);
96→
97→    return { sections };
