  1→import { useState, useRef, useCallback } from 'react';
  2→import { motion, AnimatePresence, LayoutGroup } from 'framer-motion';
  3→import { useAuth } from '../../Context/useAuth';
  4→import { submitProfileData, checkUsernameAvailability, completeOnboarding } from '../../../API/Api';
  5→import { useQueryClient } from '@tanstack/react-query';
  6→
  7→import StepProgressBar from './components/StepProgressBar';
  8→import WelcomeStep from './steps/WelcomeStep';
  9→import ProfileSetupStep from './steps/ProfileSetupStep';
 10→import InterestsStep from './steps/InterestsStep';
 11→import FeatureShowcaseStep from './steps/FeatureShowcaseStep';
 12→import FirstActionStep from './steps/FirstActionStep';
 13→
 14→import './OnboardingWizard.css';
 15→
 16→const TOTAL_STEPS = 5;
 17→
 18→const slideVariants = {
 19→    enter: (direction) => ({
 20→        x: direction > 0 ? 80 : -80,
 21→        opacity: 0,
 22→    }),
 23→    center: {
 24→        x: 0,
 25→        opacity: 1,
 26→    },
 27→    exit: (direction) => ({
 28→        x: direction > 0 ? -80 : 80,
 29→        opacity: 0,
 30→    }),
 31→};
 32→
 33→const slideTransition = {
 34→    type: 'spring',
 35→    stiffness: 350,
 36→    damping: 32,
 37→    mass: 0.8,
 38→};
 39→
 40→const OnboardingWizard = ({ onComplete, userExists }) => {
 41→    const { session, user } = useAuth();
 42→    const queryClient = useQueryClient();
 43→
 44→    const [currentStep, setCurrentStep] = useState(userExists ? 2 : 0);
 45→    const [direction, setDirection] = useState(1);
 46→
 47→    // Profile state
 48→    const [name, setName] = useState('');
 49→    const [bio, setBio] = useState('');
 50→    const [setupUsername, setSetupUsername] = useState('');
 51→    const [usernameAvailable, setUsernameAvailable] = useState(null);
 52→    const [usernameChecking, setUsernameChecking] = useState(false);
 53→    const usernameCheckTimer = useRef(null);
 54→    const [profilePreview, setProfilePreview] = useState(null);
 55→    const [imageFile, setImageFile] = useState(null);
 56→    const [submitting, setSubmitting] = useState(false);
 57→
 58→    // Interests state
 59→    const [writingInterests, setWritingInterests] = useState([]);
 60→    const [writingGoal, setWritingGoal] = useState('');
 61→
 62→    const checkUsernameDebounced = useCallback((uname) => {
 63→        if (usernameCheckTimer.current) clearTimeout(usernameCheckTimer.current);
 64→        if (!uname || uname.length < 3) {
 65→            setUsernameAvailable(null);
 66→            return;
 67→        }
 68→        setUsernameChecking(true);
 69→        usernameCheckTimer.current = setTimeout(async () => {
 70→            try {
 71→                const result = await checkUsernameAvailability(uname);
 72→                setUsernameAvailable(result.available);
 73→            } catch {
 74→                setUsernameAvailable(null);
 75→            } finally {
 76→                setUsernameChecking(false);
 77→            }
 78→        }, 400);
 79→    }, []);
 80→
 81→    const goNext = useCallback(() => {
 82→        setDirection(1);
 83→        setCurrentStep((s) => Math.min(s + 1, TOTAL_STEPS - 1));
 84→    }, []);
 85→
 86→    const goBack = useCallback(() => {
 87→        setDirection(-1);
 88→        setCurrentStep((s) => Math.max(s - 1, 0));
 89→    }, []);
 90→
 91→    const handleSubmitProfile = useCallback(async () => {
 92→        try {
 93→            setSubmitting(true);
 94→            const formdata = new FormData();
 95→            if (imageFile) formdata.append('image', imageFile);
 96→            if (bio && name) {
 97→                formdata.append('name', name);
 98→                formdata.append('bio', bio);
 99→                if (setupUsername && setupUsername.length >= 3 && usernameAvailable !== false) {
100→                    formdata.append('username', setupUsername);
101→                }
102→            }
103→            await submitProfileData(formdata, session?.access_token);
104→            queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
105→            return true;
106→        } catch (error) {
107→            console.error('error uploading profile data:', error);
108→            return false;
109→        } finally {
110→            setSubmitting(false);
111→        }
112→    }, [imageFile, bio, name, setupUsername, usernameAvailable, session, queryClient]);
113→
114→    const handleComplete = useCallback(async (action) => {
115→        try {
116→            await completeOnboarding(session?.access_token, {
117→                writingInterests,
118→                writingGoal,
119→            });
120→        } catch (err) {
121→            console.error('non-fatal: failed to save onboarding preferences:', err);
122→        }
123→        queryClient.invalidateQueries({ queryKey: ['userData', session?.user?.id] });
124→        onComplete(action);
125→    }, [session, writingInterests, writingGoal, queryClient, onComplete]);
126→
127→    const renderStep = () => {
128→        switch (currentStep) {
129→            case 0:
130→                return <WelcomeStep key="welcome" goNext={goNext} />;
131→            case 1:
132→                return (
133→                    <ProfileSetupStep
134→                        key="profile"
135→                        goNext={goNext}
136→                        goBack={goBack}
137→                        name={name}
138→                        setName={setName}
139→                        bio={bio}
140→                        setBio={setBio}
141→                        setupUsername={setupUsername}
142→                        setSetupUsername={setSetupUsername}
143→                        usernameAvailable={usernameAvailable}
144→                        usernameChecking={usernameChecking}
145→                        profilePreview={profilePreview}
146→                        setProfilePreview={setProfilePreview}
147→                        imageFile={imageFile}
148→                        setImageFile={setImageFile}
149→                        checkUsernameDebounced={checkUsernameDebounced}
150→                        submitting={submitting}
151→                        onSubmitProfile={handleSubmitProfile}
152→                    />
153→                );
154→            case 2:
155→                return (
156→                    <InterestsStep
157→                        key="interests"
158→                        goNext={goNext}
159→                        goBack={userExists ? undefined : goBack}
160→                        writingInterests={writingInterests}
161→                        setWritingInterests={setWritingInterests}
162→                        writingGoal={writingGoal}
163→                        setWritingGoal={setWritingGoal}
164→                    />
165→                );
166→            case 3:
167→                return <FeatureShowcaseStep key="showcase" goNext={goNext} goBack={goBack} />;
168→            case 4:
169→                return (
170→                    <FirstActionStep
171→                        key="firstaction"
172→                        goBack={goBack}
173→                        writingGoal={writingGoal}
174→                        onComplete={handleComplete}
175→                    />
176→                );
177→            default:
178→                return null;
179→        }
180→    };
181→
182→    return (
183→        <div className="onboarding-wizard-overlay">
184→            <div className="onboarding-wizard-card">
185→                <LayoutGroup>
186→                    <StepProgressBar currentStep={currentStep} totalSteps={TOTAL_STEPS} />
187→                </LayoutGroup>
188→
189→                <div className="onboarding-wizard-content">
190→                    <AnimatePresence mode="wait" custom={direction}>
191→                        <motion.div
192→                            key={currentStep}
193→                            custom={direction}
194→                            variants={slideVariants}
195→                            initial="enter"
196→                            animate="center"
197→                            exit="exit"
198→                            transition={slideTransition}
199→                            className="onboarding-step-wrapper"
200→                        >
201→                            {renderStep()}
202→                        </motion.div>
203→                    </AnimatePresence>
204→                </div>
205→            </div>
206→        </div>
207→    );
208→};
209→
210→export default OnboardingWizard;
