 428→const fetchRemoteImageBuffer = async (imageUrl) => {
 429→    const controller = new AbortController();
 430→    const timeout = setTimeout(() => controller.abort(), REMOTE_IMAGE_FETCH_TIMEOUT_MS);
 431→
 432→    try {
 433→        const response = await fetch(imageUrl, {
 434→            method: 'GET',
 435→            redirect: 'follow',
 436→            signal: controller.signal,
 437→            headers: {
 438→                Accept: 'image/*,*/*;q=0.8',
 439→                'Accept-Encoding': 'identity',
 440→                'User-Agent': SHARE_IMAGE_FETCH_USER_AGENT,
 441→            },
 442→        });
 443→
 444→        if (!response.ok) {
 445→            throw new Error(`upstream image status ${response.status}`);
 446→        }
 447→
 448→        const finalUrl = response.url || imageUrl;
 449→        if (!isSafeRemoteImageUrl(finalUrl)) {
 450→            throw new Error('upstream redirected to unsafe url');
 451→        }
 452→
 453→        const contentType = String(response.headers.get('content-type') || '').toLowerCase();
 454→        if (!contentType.startsWith('image/')) {
 455→            throw new Error(`upstream content-type ${contentType || 'unknown'} is not an image`);
 456→        }
 457→        if (contentType.includes('image/svg')) {
 458→            throw new Error('svg images are not used for share previews');
 459→        }
 460→
 461→        const headerContentLength = Number(response.headers.get('content-length'));
 462→        if (Number.isFinite(headerContentLength) && headerContentLength > REMOTE_IMAGE_MAX_BYTES) {
 463→            throw new Error(`upstream content-length exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 464→        }
 465→
 466→        const arrayBuffer = await response.arrayBuffer();
 467→        const buffer = Buffer.from(arrayBuffer);
 468→
 469→        if (!buffer.length) {
 470→            throw new Error('upstream image is empty');
 471→        }
 472→        if (buffer.length > REMOTE_IMAGE_MAX_BYTES) {
 473→            throw new Error(`upstream image exceeds ${REMOTE_IMAGE_MAX_BYTES} bytes`);
 474→        }
 475→
 476→        return {
 477→            buffer,
 478→            contentType,
 479→            byteLength: buffer.length,
 480→            finalUrl,
 481→        };
 482→    } finally {
 483→        clearTimeout(timeout);
 484→    }
 485→};
