 549→app.use((req, res, next) => {
 550→    metricsState.requests += 1;
 551→    metricsState.inFlight += 1;
 552→
 553→    const startNs = process.hrtime.bigint();
 554→    let byteCount = 0;
 555→
 556→    const originalWrite = res.write.bind(res);
 557→    const originalEnd = res.end.bind(res);
 558→
 559→    res.write = (chunk, encoding, callback) => {
 560→        if (chunk) {
 561→            byteCount += Buffer.isBuffer(chunk)
 562→                ? chunk.length
 563→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 564→        }
 565→        return originalWrite(chunk, encoding, callback);
 566→    };
 567→
 568→    res.end = (chunk, encoding, callback) => {
 569→        if (chunk) {
 570→            byteCount += Buffer.isBuffer(chunk)
 571→                ? chunk.length
 572→                : Buffer.byteLength(chunk, typeof encoding === 'string' ? encoding : 'utf8');
 573→        }
 574→        return originalEnd(chunk, encoding, callback);
 575→    };
 576→
 577→    res.on('finish', () => {
 578→        metricsState.inFlight = Math.max(0, metricsState.inFlight - 1);
 579→        metricsState.responses += 1;
 580→        metricsState.bytesSent += byteCount;
 581→
 582→        const statusBucket = classifyStatusBucket(res.statusCode);
 583→        metricsState.statusBuckets[statusBucket] += 1;
 584→
 585→        const durationMs = Number(process.hrtime.bigint() - startNs) / 1_000_000;
 586→        const routeTemplate = req.route?.path
 587→            ? `${req.baseUrl || ''}${req.route.path}`
 588→            : req.path;
 589→        const routeKey = `${req.method} ${canonicalizeMetricsPath(routeTemplate)}`;
 590→
 591→        let routeStat = metricsState.routeStats.get(routeKey);
 592→        if (!routeStat) {
 593→            if (metricsState.routeStats.size >= METRICS_ROUTE_LIMIT) {
 594→                return;
 595→            }
 596→
 597→            routeStat = {
 598→                count: 0,
 599→                totalDurationMs: 0,
 600→                maxDurationMs: 0,
 601→                bytesSent: 0,
 602→                statusBuckets: { '2xx': 0, '3xx': 0, '4xx': 0, '5xx': 0, other: 0 },
 603→            };
 604→            metricsState.routeStats.set(routeKey, routeStat);
 605→        }
 606→
 607→        routeStat.count += 1;
 608→        routeStat.totalDurationMs += durationMs;
 609→        routeStat.maxDurationMs = Math.max(routeStat.maxDurationMs, durationMs);
 610→        routeStat.bytesSent += byteCount;
 611→        routeStat.statusBuckets[statusBucket] += 1;
 612→    });
 613→
 614→    next();
 615→});
