42→export const getOverallEncouragement = (personal, streakCount, freezeAvailable) => {
43→    const posts = personal?.posts_written || 0;
44→    const next = getNextMilestone(streakCount);
45→    const gap = next ? next - streakCount : 0;
46→
47→    // Milestone proximity (highest priority)
48→    if (gap === 1 && next) return `One more day and you hit ${next}. Don't stop now.`;
49→    if (gap === 2 && next) return `Two days from ${next}. You can feel it coming.`;
50→    if (gap === 3 && next && next >= 30) return `Three days from ${next}. Stay locked in.`;
51→
52→    // Just hit a milestone
53→    if (streakCount === 100) return 'Triple digits. You are the streak.';
54→    if (streakCount === 50) return 'Fifty days. Half a hundred. Relentless.';
55→    if (streakCount === 30) return 'A full month of writing. That changes a person.';
56→    if (streakCount === 14) return 'Two weeks straight. This is becoming who you are.';
57→    if (streakCount === 7) return 'One week down. The habit is forming.';
58→
59→    // Freeze awareness
60→    if (freezeAvailable && streakCount >= 7) return `${streakCount} days strong, with a safety net ready.`;
61→
62→    // General streak tiers
63→    if (streakCount > 100) return `${streakCount} days. At this point, the streak has a streak.`;
64→    if (streakCount >= 30) return "Don't break the chain — your consistency is legendary.";
65→    if (streakCount >= 14) return "Deep in the rhythm now. Your readers can feel it.";
66→    if (streakCount >= 7) return "Don't break the streak — your consistency is paying off.";
67→    if (streakCount >= 3) return 'Building momentum. Three days and counting.';
68→    if (streakCount >= 1) return 'The streak begins. Come back tomorrow to keep it alive.';
69→
70→    // Fallback: post-count based
71→    if (posts >= 7) return 'Prolific week — your readers can feel the momentum.';
72→    if (posts >= 3) return 'Solid pace this week. Keep the words flowing.';
73→    if (posts === 1) return 'You showed up. That matters more than you think.';
74→    if (posts === 0) return 'A quiet week, sometimes the best ideas need silence first.';
75→    return 'Your weekly writing at a glance.';
76→};
