 63→const ChapterReader = () => {
 64→    const { storyId, chapterId } = useParams();
 65→    const navigate = useNavigate();
 66→    const location = useLocation();
 67→    const { session } = useAuth();
 68→    const token = session?.access_token;
 69→
 70→    const { data: chapter, isLoading } = useChapter(storyId, chapterId, token);
 71→    const { data: commentCounts } = useChapterCommentCounts(chapterId, token);
 72→    const progressTimerRef = useRef(null);
 73→    const scrollRef = useRef(0);
 74→    const bodyRef = useRef(null);
 75→    const hasRestoredRef = useRef(false);
 76→
 77→    // The scrollable element is .home-parent-container, not the window
 78→    const getScrollContainer = useCallback(() =>
 79→        document.querySelector('.home-parent-container') || document.documentElement
 80→    , []);
 81→    const [contentReady, setContentReady] = useState(false);
 82→    const [activeComment, setActiveComment] = useState(null);
 83→
 84→    // Save reading progress debounced on scroll
 85→    const saveProgress = useCallback(() => {
 86→        if (!token || !storyId || !chapterId) return;
 87→        saveReadingProgress(token, storyId, chapterId, scrollRef.current).catch(() => {});
 88→    }, [token, storyId, chapterId]);
 89→
 90→    useEffect(() => {
 91→        const container = getScrollContainer();
 92→
 93→        const handleScroll = () => {
 94→            const scrollTop = container.scrollTop;
 95→            const scrollableHeight = container.scrollHeight - container.clientHeight;
 96→            scrollRef.current = scrollableHeight > 0 ? Math.min(scrollTop / scrollableHeight, 1) : 0;
 97→
 98→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
 99→            progressTimerRef.current = setTimeout(saveProgress, 3000);
100→        };
101→
102→        container.addEventListener('scroll', handleScroll, { passive: true });
103→        return () => {
104→            container.removeEventListener('scroll', handleScroll);
105→            if (progressTimerRef.current) clearTimeout(progressTimerRef.current);
106→            // Save on unmount
107→            saveProgress();
108→        };
109→    }, [saveProgress, getScrollContainer]);
110→
111→    // Restore scroll position when resuming from "Continue Reading"
112→    useEffect(() => {
113→        const savedPosition = location.state?.scrollPosition;
114→        if (!savedPosition || hasRestoredRef.current || !contentReady) return;
115→        hasRestoredRef.current = true;
116→
117→        const container = getScrollContainer();
118→        // Double rAF ensures the browser has painted Lexical content
119→        let raf1, raf2;
120→        raf1 = requestAnimationFrame(() => {
121→            raf2 = requestAnimationFrame(() => {
122→                const scrollableHeight = container.scrollHeight - container.clientHeight;
123→                if (scrollableHeight > 0) {
124→                    container.scrollTo({ top: scrollableHeight * savedPosition, behavior: 'instant' });
125→                }
126→                navigate(location.pathname, { replace: true, state: {} });
127→            });
128→        });
129→
130→        return () => {
131→            cancelAnimationFrame(raf1);
132→            cancelAnimationFrame(raf2);
133→        };
134→    }, [contentReady]);
135→
136→    // Reset state when chapter changes
137→    useEffect(() => {
138→        setContentReady(false);
139→        setActiveComment(null);
140→    }, [chapterId]);
141→
142→    // Scroll progress bar (re-runs when chapter loads so the bar element exists in the DOM)
143→    useEffect(() => {
144→        const bar = document.getElementById('chapter-progress-bar');
145→        if (!bar) return;
146→        const container = getScrollContainer();
147→
148→        const updateBar = () => {
149→            const scrollTop = container.scrollTop;
150→            const scrollableHeight = container.scrollHeight - container.clientHeight;
151→            const pct = scrollableHeight > 0 ? (scrollTop / scrollableHeight) * 100 : 0;
152→            bar.style.width = `${Math.min(pct, 100)}%`;
153→        };
154→
155→        container.addEventListener('scroll', updateBar, { passive: true });
156→        return () => container.removeEventListener('scroll', updateBar);
157→    }, [getScrollContainer, isLoading]);
158→
159→    const editorConfig = {
160→        namespace: 'ChapterReader',
161→        theme: readerTheme,
162→        nodes: [ImageNode, HeadingNode, QuoteNode],
163→        editable: false,
164→        onError(error) { console.error('Lexical error:', error); },
165→    };
166→
167→    if (isLoading) {
168→        return (
169→            <div className="chapter-reader">
170→                <div className="chapter-reader-loading">
171→                    <BeatLoader size={10} color="var(--text-muted)" />
172→                </div>
173→            </div>
174→        );
175→    }
176→
177→    if (!chapter) {
178→        return (
179→            <div className="chapter-reader">
180→                <p className="chapter-reader-error">Chapter not found.</p>
181→            </div>
182→        );
183→    }
184→
185→    const prevCh = chapter.prev_chapter;
186→    const nextCh = chapter.next_chapter;
187→
188→    return (
189→        <>
190→        {/* Progress bar — must be outside motion.div so position:fixed works */}
191→        <div className="chapter-progress-track">
192→            <div id="chapter-progress-bar" className="chapter-progress-fill" />
193→        </div>
194→
195→        <motion.div
196→            className="chapter-reader"
197→            initial={{ opacity: 0 }}
198→            animate={{ opacity: 1 }}
199→            transition={{ duration: 0.2 }}
200→        >
201→            {/* Header */}
202→            <div className="chapter-reader-header">
203→                <button
204→                    className="chapter-reader-back"
205→                    onClick={() => navigate(`/home/stories/${storyId}`)}
206→                >
207→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
208→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
209→                    </svg>
210→                </button>
211→                <div className="chapter-reader-header-info">
212→                    <span className="chapter-reader-chapter-label">Chapter {chapter.chapter_number}</span>
213→                    <h1 className="chapter-reader-title">{chapter.title}</h1>
214→                </div>
215→            </div>
216→
217→            {/* Content */}
218→            <div className="chapter-reader-body" ref={bodyRef}>
219→                <LexicalComposer initialConfig={editorConfig}>
220→                    <ReaderContent chapter={chapter} onContentReady={() => setContentReady(true)} />
221→                </LexicalComposer>
222→                <ParagraphCommentLayer
223→                    containerRef={bodyRef}
224→                    commentCounts={commentCounts}
225→                    onParagraphClick={setActiveComment}
226→                />
227→            </div>
228→
229→            {/* Comment Panel */}
230→            <AnimatePresence>
231→                {activeComment && (
232→                    <CommentPanel
233→                        chapterId={chapterId}
234→                        activeComment={activeComment}
235→                        onClose={() => setActiveComment(null)}
236→                    />
237→                )}
238→            </AnimatePresence>
239→
240→            {/* Navigation */}
241→            <div className="chapter-reader-nav">
242→                {prevCh ? (
243→                    <button
244→                        className="chapter-nav-btn chapter-nav-prev"
245→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${prevCh.id}`)}
246→                    >
247→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
248→                            <path d="M15.41 7.41L14 6l-6 6 6 6 1.41-1.41L10.83 12z"/>
249→                        </svg>
250→                        <span>Ch. {prevCh.chapter_number}: {prevCh.title}</span>
251→                    </button>
252→                ) : <div />}
253→                {nextCh ? (
254→                    <button
255→                        className="chapter-nav-btn chapter-nav-next"
256→                        onClick={() => navigate(`/home/stories/${storyId}/chapter/${nextCh.id}`)}
257→                    >
258→                        <span>Ch. {nextCh.chapter_number}: {nextCh.title}</span>
259→                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
260→                            <path d="M10 6L8.59 7.41 13.17 12l-4.58 4.59L10 18l6-6z"/>
261→                        </svg>
262→                    </button>
263→                ) : <div />}
264→            </div>
265→        </motion.div>
266→        </>
267→    );
268→};
