223→export const deleteChapterService = async (storyId, chapterId, userId) => {
224→    if (!storyId || !chapterId || !userId) {
225→        throw { status: 400, error: 'storyId, chapterId, and userId are required' };
226→    }
227→
228→    await verifyStoryOwnership(storyId, userId);
229→
230→    const { error } = await supabase
231→        .from('chapters')
232→        .delete()
233→        .eq('id', chapterId)
234→        .eq('story_id', storyId);
235→
236→    if (error) {
237→        console.error('supabase error deleting chapter:', error.message);
238→        throw { status: 500, error: 'failed to delete chapter' };
239→    }
240→
241→    return { message: 'chapter deleted' };
242→};
