  1→import React, { useState, useCallback } from 'react';
  2→import { useNavigate, useParams } from 'react-router-dom';
  3→import { useAuth } from '../../../Context/useAuth';
  4→import { useStoryDetail } from '../hooks/useStoryData';
  5→import { useCreateChapter, useUpdateChapter, useDeleteChapter, useReorderChapters } from '../hooks/useStoryMutations';
  6→import { motion, AnimatePresence } from 'framer-motion';
  7→import { BeatLoader } from 'react-spinners';
  8→import './StoryChapterManager.css';
