 10→const StoryChapterManager = () => {
 11→    const { storyId } = useParams();
 12→    const navigate = useNavigate();
 13→    const { session } = useAuth();
 14→    const token = session?.access_token;
 15→
 16→    const { data: story, isLoading } = useStoryDetail(storyId, token);
 17→    const createChapter = useCreateChapter(token);
 18→    const updateChapter = useUpdateChapter(token);
 19→    const deleteChapter = useDeleteChapter(token);
 20→    const reorderChapters = useReorderChapters(token);
 21→
 22→    const [draggedIdx, setDraggedIdx] = useState(null);
 23→    const [showNewChapterInput, setShowNewChapterInput] = useState(false);
 24→    const [newChapterTitle, setNewChapterTitle] = useState('');
 25→
 26→    const chapters = story?.chapters || [];
 27→
 28→    const handleAddChapter = () => {
 29→        const title = newChapterTitle.trim() || `Chapter ${chapters.length + 1}`;
 30→        createChapter.mutate({ storyId, title }, {
 31→            onSuccess: () => {
 32→                setNewChapterTitle('');
 33→                setShowNewChapterInput(false);
 34→            },
 35→        });
 36→    };
 37→
 38→    const handleNewChapterKeyDown = (e) => {
 39→        if (e.key === 'Enter') {
 40→            e.preventDefault();
 41→            handleAddChapter();
 42→        } else if (e.key === 'Escape') {
 43→            setShowNewChapterInput(false);
 44→            setNewChapterTitle('');
 45→        }
 46→    };
 47→
 48→    const handleToggleStatus = (chapter) => {
 49→        const newStatus = chapter.status === 'published' ? 'draft' : 'published';
 50→        updateChapter.mutate({
 51→            storyId,
 52→            chapterId: chapter.id,
 53→            data: { status: newStatus },
 54→        });
 55→    };
 56→
 57→    const handleDeleteChapter = (e, chapter) => {
 58→        e.stopPropagation();
 59→        if (window.confirm(`Delete "${chapter.title}"? This cannot be undone.`)) {
 60→            deleteChapter.mutate({ storyId, chapterId: chapter.id });
 61→        }
 62→    };
 63→
 64→    // Drag & drop reorder
 65→    const handleDragStart = useCallback((idx) => {
 66→        setDraggedIdx(idx);
 67→    }, []);
 68→
 69→    const handleDragOver = useCallback((e) => {
 70→        e.preventDefault();
 71→    }, []);
 72→
 73→    const handleDrop = useCallback((targetIdx) => {
 74→        if (draggedIdx === null || draggedIdx === targetIdx) {
 75→            setDraggedIdx(null);
 76→            return;
 77→        }
 78→        const reordered = [...chapters];
 79→        const [moved] = reordered.splice(draggedIdx, 1);
 80→        reordered.splice(targetIdx, 0, moved);
 81→        const chapterOrder = reordered.map(c => c.id);
 82→        reorderChapters.mutate({ storyId, chapterOrder });
 83→        setDraggedIdx(null);
 84→    }, [draggedIdx, chapters, storyId, reorderChapters]);
 85→
 86→    if (isLoading) {
 87→        return (
 88→            <div className="chapter-manager">
 89→                <div className="chapter-manager-loading">
 90→                    <BeatLoader size={10} color="var(--text-muted)" />
 91→                </div>
 92→            </div>
 93→        );
 94→    }
 95→
 96→    if (!story) {
 97→        return (
 98→            <div className="chapter-manager">
 99→                <p className="chapter-manager-error">Story not found.</p>
100→            </div>
101→        );
102→    }
103→
104→    return (
105→        <motion.div
106→            className="chapter-manager"
107→            initial={{ opacity: 0, y: 12 }}
108→            animate={{ opacity: 1, y: 0 }}
109→            transition={{ duration: 0.2 }}
110→        >
111→            <div className="chapter-manager-header">
112→                <button className="chapter-manager-back" onClick={() => navigate('/home/stories/dashboard')}>
113→                    <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="var(--text-secondary)">
114→                        <path d="M20 11H7.83l5.59-5.59L12 4l-8 8 8 8 1.41-1.41L7.83 13H20v-2z"/>
115→                    </svg>
116→                </button>
117→                <div className="chapter-manager-title-section">
118→                    <h2 className="chapter-manager-title">{story.title}</h2>
119→                    <span className="chapter-manager-subtitle">
120→                        {chapters.length} chapter{chapters.length !== 1 ? 's' : ''}
121→                    </span>
122→                </div>
123→                <button
124→                    className="chapter-manager-edit-story-btn"
125→                    onClick={() => navigate(`/home/stories/${storyId}/edit`)}
126→                >
127→                    Edit Details
128→                </button>
129→            </div>
130→
131→            <div className="chapter-manager-actions">
132→                {showNewChapterInput ? (
133→                    <div className="chapter-manager-new-input-row">
134→                        <input
135→                            className="chapter-manager-new-title-input"
136→                            type="text"
137→                            value={newChapterTitle}
138→                            onChange={(e) => setNewChapterTitle(e.target.value)}
139→                            onKeyDown={handleNewChapterKeyDown}
140→                            placeholder={`Chapter ${chapters.length + 1}`}
141→                            maxLength={200}
142→                            autoFocus
143→                        />
144→                        <button
145→                            className="chapter-manager-add-btn"
146→                            onClick={handleAddChapter}
147→                            disabled={createChapter.isPending}
148→                        >
149→                            {createChapter.isPending ? (
150→                                <BeatLoader size={6} color="var(--bg-primary)" />
151→                            ) : (
152→                                'Add'
153→                            )}
154→                        </button>
155→                        <button
156→                            className="chapter-manager-cancel-btn"
157→                            onClick={() => { setShowNewChapterInput(false); setNewChapterTitle(''); }}
158→                        >
159→                            Cancel
160→                        </button>
161→                    </div>
162→                ) : (
163→                    <button
164→                        className="chapter-manager-add-btn"
165→                        onClick={() => setShowNewChapterInput(true)}
166→                    >
167→                        + Add Chapter
168→                    </button>
169→                )}
170→            </div>
171→
172→            {chapters.length === 0 ? (
173→                <div className="chapter-manager-empty">
174→                    <p>No chapters yet. Add your first chapter to start writing.</p>
175→                </div>
176→            ) : (
177→                <div className="chapter-manager-list">
178→                    <AnimatePresence>
179→                        {chapters.map((chapter, idx) => (
180→                            <motion.div
181→                                key={chapter.id}
182→                                className={`chapter-manager-item ${draggedIdx === idx ? 'chapter-manager-item-dragging' : ''}`}
183→                                initial={{ opacity: 0, y: 8 }}
184→                                animate={{ opacity: 1, y: 0 }}
185→                                exit={{ opacity: 0, x: -20 }}
186→                                draggable
187→                                onDragStart={() => handleDragStart(idx)}
188→                                onDragOver={handleDragOver}
189→                                onDrop={() => handleDrop(idx)}
190→                            >
191→                                <div className="chapter-manager-item-drag">
192→                                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="var(--text-muted)">
193→                                        <path d="M11 18c0 1.1-.9 2-2 2s-2-.9-2-2 .9-2 2-2 2 .9 2 2zm-2-8c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0-6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm6 4c1.1 0 2-.9 2-2s-.9-2-2-2-2 .9-2 2 .9 2 2 2zm0 2c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2zm0 6c-1.1 0-2 .9-2 2s.9 2 2 2 2-.9 2-2-.9-2-2-2z"/>
194→                                    </svg>
195→                                </div>
196→
197→                                <div
198→                                    className="chapter-manager-item-content"
199→                                    onClick={() => navigate(`/home/stories/${storyId}/chapter/${chapter.id}/edit`)}
200→                                >
201→                                    <span className="chapter-manager-item-number">
202→                                        Ch. {chapter.chapter_number}
203→                                    </span>
204→                                    <span className="chapter-manager-item-title">
205→                                        {chapter.title}
206→                                    </span>
207→                                    <span className="chapter-manager-item-words">
208→                                        {(chapter.word_count || 0).toLocaleString()} words
209→                                    </span>
210→                                </div>
211→
212→                                <div className="chapter-manager-item-actions">
213→                                    <button
214→                                        className={`chapter-status-toggle ${chapter.status === 'published' ? 'chapter-status-published' : 'chapter-status-draft'}`}
215→                                        onClick={(e) => {
216→                                            e.stopPropagation();
217→                                            handleToggleStatus(chapter);
218→                                        }}
219→                                        title={chapter.status === 'published' ? 'Unpublish' : 'Publish'}
220→                                    >
221→                                        {chapter.status === 'published' ? 'Published' : 'Draft'}
222→                                    </button>
223→                                    <button
224→                                        className="story-action-btn story-action-btn-danger"
225→                                        onClick={(e) => handleDeleteChapter(e, chapter)}
226→                                        title="Delete chapter"
227→                                    >
228→                                        <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="currentColor">
229→                                            <path d="M6 19c0 1.1.9 2 2 2h8c1.1 0 2-.9 2-2V7H6v12zM19 4h-3.5l-1-1h-5l-1 1H5v2h14V4z"/>
230→                                        </svg>
231→                                    </button>
232→                                </div>
233→                            </motion.div>
234→                        ))}
235→                    </AnimatePresence>
236→                </div>
237→            )}
238→        </motion.div>
239→    );
240→};
241→
242→export default StoryChapterManager;
