```javascript
const saveTimerRef = useRef(null);
const [isSaving, setIsSaving] = useState(false);
const [hasChanges, setHasChanges] = useState(false);
const [lastSavedAt, setLastSavedAt] = useState(null);
const draftIdRef = useRef(draftId); // keep in sync with prop

// Autosave — debounce 30s from last change
useEffect(() => {
    if (!hasChanges || !editorState) return;
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(() => {
        handleDraftSave(false);
    }, 30000);
    return () => { if (saveTimerRef.current) clearTimeout(saveTimerRef.current); };
}, [editorState, hasChanges]);

const handleDraftSave = async (showFeedback = true) => {
    if (!editorState) return;
    if (showFeedback) setIsSaving(true);
    try {
        const body = {
            title: title || '',
            content: editorState,
            ...(draftIdRef.current && { draft_id: draftIdRef.current }),
            ...(promptId && { prompt_id: promptId }),
        };
        const result = await saveDraft(session?.access_token, body);
        if (result?.id && !draftIdRef.current) {
            draftIdRef.current = result.id;
            onDraftIdCreated?.(result.id);
        }
        setHasChanges(false);
        setLastSavedAt(new Date());
    } catch (err) {
        console.error('autosave failed:', err);
    } finally {
        if (showFeedback) setIsSaving(false);
    }
};

const handlePublish = async () => {
    // If no draft ID yet, save first to create one
    if (!draftIdRef.current) {
        await handleDraftSave(false);
    }
    if (!draftIdRef.current) return; // save failed
    setIsSending(true);
    try {
        const result = await publishDraft(session?.access_token, draftIdRef.current);
        if (result) {
            await invalidateCreatedJournalQueries();
            // also invalidate drafts query
            queryClient.invalidateQueries({ queryKey: ['journal-drafts', userId] });
            setHasChanges(false);
            onCloseOnSave();
            addUploadImagesPath([]);
        }
    } catch (err) {
        console.error('publish failed:', err);
    } finally {
        setIsSending(false);
    }
};
```

